using sv_816f8d487f2c4852915400d196c056aa.Client.Services;

namespace sv_816f8d487f2c4852915400d196c056aa.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.FromHours(-5)),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.FromHours(-5)), "Package picked up", "New York, NY"),
                new(new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.FromHours(-5)), "Arrived at sorting facility", "Philadelphia, PA"),
                new(new DateTimeOffset(2026, 5, 22, 8, 15, 0, TimeSpan.FromHours(-6)), "In transit to destination", "Chicago, IL"),
            }),

        ["PKG-002"] = new ShipmentDetails(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.FromHours(-7)),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.FromHours(-7)), "Package picked up", "Los Angeles, CA"),
                new(new DateTimeOffset(2026, 5, 19, 16, 0, 0, TimeSpan.FromHours(-7)), "Out for delivery", "San Francisco, CA"),
                new(new DateTimeOffset(2026, 5, 19, 18, 45, 0, TimeSpan.FromHours(-7)), "Delivered - Left at front door", "San Francisco, CA"),
            }),

        ["PKG-003"] = new ShipmentDetails(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 15, 0, 0, TimeSpan.FromHours(-5)),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 22, 7, 0, 0, TimeSpan.FromHours(-5)), "Label created", "Dallas, TX"),
            }),
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

